INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68027f36e3c98b0941765cb5', '老牌酒店，很大，房间很多。基础房型房间不大。但是设计合理，设施还是挺完备的。都有咖啡机，我很喜欢。服务也比较到位。', '["https://dimg04.c-ctrip.com/images/0232i12000c03glfjF412_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233t12000c03bri84181_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000c03gwkpA64C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233m12000c035lo1FAE0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230y12000c038m8n7990_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233g12000c036ji6E374_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000c03e70226DD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-25', '花园大床房', '大床房', '商务出差', 57, 0, 69, 6, '["房间设施","前台服务","客房服务"]'::jsonb, '房间设施', '前台服务', '客房服务'),
('68027f36e3c98b0941765cb6', '卫生安静，大气经典。依然是处于第一梯队的酒店，服务一直是标杆，尤其谢谢房务阿姨，还有大堂的高挑姐姐，外籍工作人员，还有Whaley。贴心的现烤曲奇还有伴手礼，太棒啦', '["https://dimg04.c-ctrip.com/images/0236812000bq8rr9qFCCC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000bq8ltkhC5D9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233y12000bq8l3gj0152_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-23', '花园大床房', '大床房', '情侣出游', 82, 0, 3, 8, '["整体满意度","客房服务","前台服务"]'::jsonb, '整体满意度', '客房服务', '前台服务'),
('68027f36e3c98b0941765cb7', '难忘的酒店。虽然家具有点旧，无usd充电插口，但服务人员把自己的借我了，很好。。', '["https://dimg04.c-ctrip.com/images/0235212000c8eh1y5A2F5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230s12000c8eh0w08732_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230412000c8eh25998B5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-24', '花园大床房', '大床房', '朋友出游', 40, 0, 8, 6, '["房间设施","前台服务"]'::jsonb, '房间设施', '前台服务', NULL),
('68027f36e3c98b0941765cb8', '酒店自带一个很漂亮的大园林，房间干净，前台服务热情，下次还会再来。', '["https://dimg04.c-ctrip.com/images/0233a12000cggzks22CA5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235p12000cggtji131A1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232b12000cggxh755F48_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232d12000cggz20pED06_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-26', '红棉双床套房', '套房', '朋友出游', 33, 0, 3, 6, '["整体满意度","卫生状况","前台服务"]'::jsonb, '整体满意度', '卫生状况', '前台服务'),
('68027f36e3c98b0941765cb9', '房间卫生条件优秀，就是停车场不能直达大堂，大堂里面可算富丽堂皇，不亏是白金五星酒店，房间设施不错，应该是都更新过的，唯一的遗憾是电视信号不假，只有五个频道能看，有点遗憾，早餐也挺丰富的，吃的很满意！', '["https://dimg04.c-ctrip.com/images/0235c12000bhusjtbA301_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235c12000bhuszalF80E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235712000bhus97iB8DA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231e12000bhuq7d5A7FF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230k12000bhumxfx5DBA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-06-25', '红棉大床套房', '套房', '家庭亲子', 99, 0, 37, 8, '["房间设施","卫生状况","餐饮设施"]'::jsonb, '房间设施', '卫生状况', '餐饮设施'),
('68027f41e3c98b0941765cba', '超级满意 房间内有个大大的浴缸 晚上正好和孩子们一起泡浴~ 最后一天中午参观了博物馆又去了小公园看瀑布 附近步行5分钟就有点都德 大满足
环境：超赞', '["https://dimg04.c-ctrip.com/images/0203w12000bthrhn58327_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0236812000bthekuc8550_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233012000bthm7l9E83E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233z12000bthiaejF144_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-03', '花园双床房', '双床房', '家庭亲子', 74, 0, 5, 7, '["房间设施","周边配套","整体满意度"]'::jsonb, '房间设施', '周边配套', '整体满意度'),
('68027f41e3c98b0941765cbb', '来办签证材料缺失临时需要在广州过一夜什么东西都没有准备，仓促定了花园酒店。因为以前也住过本来没有什么期待，但是前台小姐姐Joyce非常体贴让疲惫的我心情好了很多??还给我们升级了房型，让我这一次的入住体验直接拉???！双人间床帘一拉互不打扰炒鸡喜欢！下次还会选择花园酒店！', '["https://dimg04.c-ctrip.com/images/0232i12000c1sbxm8996F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230w12000c1sdg6dC8A0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230312000c1sf7t1C1FD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233612000c1slh1s65D9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-01', '花园双床房', '双床房', '独自旅行', 136, 0, 4, 8, '["前台服务","整体满意度","房间设施"]'::jsonb, '前台服务', '整体满意度', '房间设施'),
('68027f41e3c98b0941765cbc', '前台小姐姐态度很好，还送我了花花，和小点心。
但酒店有点老了，墙纸有些位置有脱落，一些死角灰层有点厚', '["https://dimg04.c-ctrip.com/images/0235v2215g8njewio4E2D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235t2234cfdvkmk06EE9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e2234cfdwchn48F00_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-09-04', '花园双床房', '双床房', '家庭亲子', 50, 0, 29, 7, '["前台服务","卫生状况"]'::jsonb, '前台服务', '卫生状况', NULL),
('68027f41e3c98b0941765cbd', '第一次入住，都给升级为套间，服务员们很热情，不错，住的舒服……路边在维修，房间有些吵，好在白天外出时间长，晚上短暂吵，还能接受的，下次还会选择', '["https://dimg04.c-ctrip.com/images/0237312000bswfqe0779A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000bsw3xd7DD6B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234f12000bswgz164B84_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-01', '花园大床房', '大床房', '家庭亲子', 71, 0, 7, 6, '["整体满意度","安静程度","前台服务"]'::jsonb, '整体满意度', '安静程度', '前台服务'),
('68027f41e3c98b0941765cbe', '文化，细节，美食，亲子，度假！
对于老广有一定情怀的，除了白天鹅，花园酒店是一个非常值得推荐的打卡酒店～', '["https://dimg04.c-ctrip.com/images/0230u12000c28svkb41DB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232112000c28xkvh0A6D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236g12000c28wf7bC04A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236f12000c291796E6E0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231p12000c293wuuC574_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-03', '花园大床房', '大床房', '家庭亲子', 52, 0, 7, 5, '["整体满意度","餐饮设施"]'::jsonb, '整体满意度', '餐饮设施', NULL),
('68027f41e3c98b0941765cbf', '抓住暑假的尾巴，来到传说中的花园酒店，住店体验非常的好！环境好靓，食品出品干净、精致、味道好！期待下次再来～', '["https://dimg04.c-ctrip.com/images/0230l12000c0qffzi5A1A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230a12000c0qflc8BD56_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234z12000c0qfnq549BF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234112000c0qfqksF293_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235s12000c0qfnm4C40A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-28', '红棉大床套房', '套房', '家庭亲子', 54, 0, 1, 6, '["整体满意度","餐饮设施","卫生状况"]'::jsonb, '整体满意度', '餐饮设施', '卫生状况'),
('68027f41e3c98b0941765cc0', '服务到位，清静卫生', '["https://dimg04.c-ctrip.com/images/0233h12000coy04svA6C1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-12-07', '花园行政大床套房', '套房', '商务出差', 9, 0, 10, 4, '["客房服务","卫生状况","安静程度"]'::jsonb, '客房服务', '卫生状况', '安静程度'),
('68027f41e3c98b0941765cc1', '昨天入住广州花园酒店，给我不一样的感受，接待我们的是Viria和Ariel两位美女，她们周到的介绍，细心的服务，让我们宾至如归，她们友好耐心的服务和美美的气质让我们感到花园的服务员是有良好素质和优质服意识的，从此可看到酒店的管理不错，再加上有历史的优美环境，干净整洁的房间，我们马上决定在这住9晚，续订了。很开心。', '["https://dimg04.c-ctrip.com/images/0234712000bxpc4b1230F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-17', '红棉双床套房', '套房', '家庭亲子', 157, 0, 16, 9, '["前台服务","整体满意度","卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况'),
('68027f41e3c98b0941765cc2', '广州老字号酒店，地理位置非常好，地铁口出来100米，环境好，服务很好，前台办理员Niki很漂亮的小姐姐，给我们升级了一个套房，真的是太好了', '["https://dimg04.c-ctrip.com/images/0231612000dxxmlr7C596_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233512000dxxle7u17A1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235712000dxxmq4v2B17_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230s12000dxxminiEFF3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-10', '城央绿意大床房', '大床房', '家庭亲子', 69, 0, 32, 7, '["交通便利性","前台服务","整体满意度"]'::jsonb, '交通便利性', '前台服务', '整体满意度'),
('68027f41e3c98b0941765cc3', '原来广州花园酒店也是出自顶尖的华裔建筑大师贝聿铭之手，感觉好几个中欧航空公司的空乘都是专门入住花园酒店的。

?环境亮点：地铁站上来即刻就到酒店 ～ 一进入酒店大厅，你就会为这里设计上深深蕴含的中国传统文化特色而震惊！大堂是大跨度无柱设计、富丽堂皇！正对着的是150平方米的红楼梦《大观园》金箔壁画～ 旁边就是18米双瀑布美景餐厅，在这里用早餐还是蛮心旷神怡的～ 

??房型服务：这次预定的是花园大床房，从房间内的落地玻璃窗就可直接眺望到瀑布，繁华的市区也能有一丝绿意盎然～ 室内的大浴缸令人眼前一亮。不过两天下来并没有专门去泡澡，因为酒店内的桑拿更是给力哦！

??设施齐全：个人原因总是喜欢体验各酒店的泳池和桑拿浴室，而广州也许因为国际客户特别多，因此连桑拿房都分了干湿蒸，也有冰凉的0度冰水给大家冷热交替！ 很多4星酒店这个部分都被搁置不被重视，但花园酒店令人惊喜！

??周边玩乐：酒店里现在有一个广州酒店博物馆～ 看了实在唏嘘。原来1996年，广州花园酒店给员工的服装费就有1600rmb，果然差距好大！花园酒店里还有好几家米其林星级餐厅！中餐、西餐各占2个席位！广州泰安门勇夺广州米其林二星！3楼桃园馆更是以地道粤菜蝉联米其林餐盘奖！可惜这次来没有机会了，下次必须泰安门走起！', '["https://dimg04.c-ctrip.com/images/0202e12000blp4n1l96C1_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0233012000blohrj364AC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234o12000bloorduFFC1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235f12000blohdun531C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232v12000blone3a08CD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230c12000blom68t8254_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231q12000blook9fAFC4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000bloipox7EA4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-08', '花园大床房', '大床房', '情侣出游', 545, 1, 6, 9, '["公共设施","交通便利性","餐饮设施"]'::jsonb, '公共设施', '交通便利性', '餐饮设施'),
('68027f4ce3c98b0941765cc4', '六一老婆生日，因为唔系假日，出唔捣外，所以就拣花园酒店住返晚，贪佢离公司同学校近，就脚。第二次入住喇，老婆对安排好满意。感谢大堂既靓女RAIN，送左份好靓既美颜用品手信，啱晒老婆用。不足：泳池D水有浊。', '["https://dimg04.c-ctrip.com/images/0232112000bcaotxyBE4C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233f12000bcaktxt1DC5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230312000bcai2si9598_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232s12000bcag9oyFE0C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230t12000bcaiqyl3896_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000bcapltlE9B3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236512000bcajt2u6545_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231312000bcakih53455_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235012000bcaky05087D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-02', '红棉双床套房', '套房', '家庭亲子', 101, 0, 54, 7, '["周边配套","前台服务","公共设施"]'::jsonb, '周边配套', '前台服务', '公共设施'),
('68027f4ce3c98b0941765cc5', '房间设施非常好??', '["https://dimg04.c-ctrip.com/images/0233v12000cmp9b2oB6F8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-24', '红棉大床套房', '套房', '商务出差', 9, 0, 2, 3, '["房间设施"]'::jsonb, '房间设施', NULL, NULL),
('68027f4ce3c98b0941765cc6', '入住花园酒店是个巧合，航司通知停飞改签至第二天，临时找的酒店。第一眼的印象非常好，大堂的布置是歌剧魅影，我们是看完歌剧后入住的，孩子看到后兴奋的不得了。前台Mancy给办的入住，给我们升级了套房，还送了我们欢迎花朵。服务周到细心，知道我们第一次入住给我们介绍了四楼的博物馆和油画展。办理手续非常顺利，动作娴熟，没有等待很久也是直接拿的房。广州玩了几天，下午下雨就直接去观展，还在酒店用了晚膳，体验感很不错，以后会是我再来广州首选的酒店。', '["https://dimg04.c-ctrip.com/images/0231h12000bt9ye2fE4F6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235n12000bt9yr154D91_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235712000bt9v1xuF640_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236812000bt9x4cj4555_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236512000bta2u71141B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234w12000bt9tkq93891_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235s12000bt9tkqb2175_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234812000bt9vkdr98EB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234c12000bta2uzpCEC9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-02', '花园双床房', '双床房', '家庭亲子', 218, 0, 5, 9, '["前台服务","整体满意度","退房/入住效率"]'::jsonb, '前台服务', '整体满意度', '退房/入住效率'),
('68027f4ce3c98b0941765cc7', '极具岭南特色的后花园景致和荔湾亭美食 值得再来 也是第一次游广州的最佳之选', '["https://dimg04.c-ctrip.com/images/0236f12000c26pct078A6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235h12000c26h7j76FBF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236c12000c26ksx56983_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230u12000c26lta729E3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234212000c26pembC412_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231v12000c26nkwo1F5B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000c26i9ilB6FD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233912000c26o8w3377E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235c12000c26fmud416E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-03', '花园大床房', '大床房', '情侣出游', 37, 0, 13, 5, '["周边配套","整体满意度"]'::jsonb, '周边配套', '整体满意度', NULL),
('68027f4ce3c98b0941765cc8', '办理入住时间比较长，排队地方设置不明显导致有人插队。早餐觉得不如其他五星，房间也的确有些年头。就住个情怀打个卡吧，五星好评。', '["https://dimg04.c-ctrip.com/images/0236u12000bufnot49F6E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233m12000bufqgpj71BF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000bufpnma82CF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235f12000bufmxg6C764_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234c12000bufj9td6255_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230y12000bufnfsu46BA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-06', '花园大床房', '大床房', '独自旅行', 62, 0, 10, 6, '["退房/入住效率","餐饮设施","房间设施"]'::jsonb, '退房/入住效率', '餐饮设施', '房间设施'),
('68027f4ce3c98b0941765cc9', '酒店很多外宾，上车下车无人帮拿行李，完全感受不到白金五星酒店的服务，略有失望', '["https://dimg04.c-ctrip.com/images/0236f12000c6zqmh2AE36_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234712000c6zo4su6EC3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3, 3, '2023-09-20', '花园大床房', '大床房', '家庭亲子', 38, 0, 1, 6, '["前台服务","客房服务"]'::jsonb, '前台服务', '客房服务', NULL),
('68027f4ce3c98b0941765cca', '我们14点到的，但是要两个小时以后才能办入住，一般酒店都会免费升房，但是酒店告诉我们如果想要立即入住的话需要自己加钱才能升房哦！也许是周末人比较多吧！价钱比我后面住的喜来登贵，但是总体来说环境，设施，设计，服务等都要改进！', '["https://dimg04.c-ctrip.com/images/0231o12000bg3eq040670_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231r12000bg38y7l80BD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-19', '花园大床房', '大床房', '家庭亲子', 111, 0, 3, 6, '["退房/入住效率","性价比","整体满意度"]'::jsonb, '退房/入住效率', '性价比', '整体满意度'),
('68027f4ce3c98b0941765ccb', '房间虽然不是很新也不大，两个人住的还是挺舒适的
住这里附加值非常高，后花园和博物馆值得带小孩打卡
不用出酒店就能吃到好吃的下午茶
来广州的第一天愉快的吃吃喝喝太合适了', '["https://dimg04.c-ctrip.com/images/0235s12000bl1s6x57DEC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235v12000bl0dqs1DA00_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000bl1qql47152_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232k12000bl1amuk13D2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235s12000bl0w1xk784E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234f12000bl0ivcnE7F1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234412000bl1utpbB002_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237212000bl1toqyCC06_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000bl0fdg695F7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-06', '花园双床房', '双床房', '家庭亲子', 83, 0, 1, 7, '["整体满意度","公共设施","餐饮设施"]'::jsonb, '整体满意度', '公共设施', '餐饮设施'),
('68027f4ce3c98b0941765ccc', '不愧是花园酒店，自带的花园超级漂亮，餐饮也很出色，服务热情。', '["https://dimg04.c-ctrip.com/images/0235s12000cbeqw7c6F2E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233112000cbeqgh0843A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-03', '花园大床房', '大床房', '家庭亲子', 30, 0, 3, 6, '["餐饮设施","前台服务","整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度'),
('68027f4ce3c98b0941765ccd', '服务非常好，不愧是老牌五星酒店。', '["https://dimg04.c-ctrip.com/images/0236912000chqj4vb7C32_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235l12000chqb842F8E0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232912000chq5rnlA2A9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-01', '花园大床房', '大床房', '商务出差', 16, 0, 10, 4, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027f57e3c98b0941765cce', '房间宽敞舒适，设施完备齐全，服务温馨周到，尤其是客房服务中心小刘姑娘真诚热情、细致入微，必须点赞??', '["https://dimg04.c-ctrip.com/images/0232h12000jcrmy650DA3_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0233y12000jcro9s21AEE_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2025-03-27', '花园大床房', '大床房', '商务出差', 50, 0, 37, 8, '["房间设施","客房服务","整体满意度"]'::jsonb, '房间设施', '客房服务', '整体满意度'),
('68027f57e3c98b0941765ccf', '服务有求必应，交通方便，动静脉分流合理，一楼早晚自助餐品种还行。建议大楼外玻璃清洗干净，看外面景色模糊。', '["https://dimg04.c-ctrip.com/images/0235o12000byiwdbg4F84_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230412000byj0s2w810D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231h12000byiw5y04BBC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236j12000byj93936A11_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-08-20', '花园大床房', '大床房', '家庭亲子', 52, 0, 16, 7, '["前台服务","交通便利性","餐饮设施"]'::jsonb, '前台服务', '交通便利性', '餐饮设施'),
('68027f57e3c98b0941765cd0', '第一次来广州，在选入住酒店的时候对比了好多酒店选的花园酒店，酒店一级棒，大堂恢宏气派，酒店特别有自己的文化和特色，房间很漂亮整洁，服务人员特别热情周到，办理入住的小姐姐贴心的给我们送了鲜花，还推荐我们参观酒店的博物馆和后花园等网红打卡地，参观了一圈酒店晚上我们还在瀑布餐厅享受了一顿丰盛的自助餐，退房时候大堂的小美女帮我们办理了快速退房还送我们宝格丽的洗护套装，非常奈斯。下次来广州首选花园酒店', '["https://dimg04.c-ctrip.com/images/0202312000bmffi4m7D1D_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0230d12000bmf4zjj5A88_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231f12000bmfdsm0B57B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235n12000bmf5ktuB681_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-10', '花园双床房', '双床房', '家庭亲子', 197, 0, 3, 9, '["整体满意度","前台服务","退房/入住效率"]'::jsonb, '整体满意度', '前台服务', '退房/入住效率'),
('68027f57e3c98b0941765cd1', '酒店环境十分好，后花园瀑布值得一逛。但房间设施有些老旧，玻璃窗全是灰，淋浴和厕所共用一扇移门，推拉不方便，很费劲。洗手池台面也不太干净。', '["https://dimg04.c-ctrip.com/images/0235v12000bqx26ct1D1E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234z12000bqx52d099EC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-07-25', '花园双床房', '双床房', '家庭亲子', 68, 1, 15, 8, '["房间设施","卫生状况"]'::jsonb, '房间设施', '卫生状况', NULL),
('68027f57e3c98b0941765cd2', '设施虽然有点儿旧，但是胜在环境好，服务好，食物新鲜，交通非常安全便利，后花园很美，瀑布漂亮，鱼很大。', '["https://dimg04.c-ctrip.com/images/0234212000bzhuyy19E23_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234e12000bzht2ql18F1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-08-23', '红棉大床套房', '套房', '家庭亲子', 50, 0, 2, 7, '["交通便利性","整体满意度","餐饮设施"]'::jsonb, '交通便利性', '整体满意度', '餐饮设施'),
('68027f57e3c98b0941765cd3', '父亲节给父母订的酒店，家住广州的老人家花园酒店对他们来说再熟悉不过了，酒店很贴心的升级了套房，入住用餐的过程中都给予特别关照，父母对此次体验非常满意，充分体现广州老牌五星级的服务水平????', '["https://dimg04.c-ctrip.com/images/0204j12000bfs6h1s70FE_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0236r12000bfrrimaB9CB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-17', '花园双床房', '双床房', '家庭亲子', 95, 0, 26, 7, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('68027f57e3c98b0941765cd4', '花园酒店装饰富丽堂皇，美轮美奂。酒店分酒店大楼和花园大厦两座Y型大楼。前台服务很 nice,betty joyce 两人一起接待，感觉宾至如归。', '["https://dimg04.c-ctrip.com/images/0232y12000boj1bun08CB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235z12000boj1fedF9E1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232z12000boj1h452699_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-17', '花园大床房', '大床房', '商务出差', 72, 0, 4, 7, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027f57e3c98b0941765cd5', '服务和环境一流水平，不愧为五星级酒店。', '["https://dimg04.c-ctrip.com/images/0234v12000cfsmbb119A3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236a12000cfslnzgC538_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231212000cfsmero2F99_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236v12000cfsm3zrB164_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-23', '红棉双床套房', '套房', '家庭亲子', 19, 0, 11, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027f57e3c98b0941765cd6', '挺好，送了小点心，结婚纪念日还送了小布置，美中不足泳池维修，没玩上水', '["https://dimg04.c-ctrip.com/images/0232w12000c6xjzou1C7E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-20', '红棉大床套房', '套房', '家庭亲子', 34, 0, 2, 6, '["客房服务","公共设施","整体满意度"]'::jsonb, '客房服务', '公共设施', '整体满意度'),
('68027f57e3c98b0941765cd7', '飞机延误，到酒店已凌晨，酒店接待认真负责，还给我们房间升了级，非常满意', '["https://dimg04.c-ctrip.com/images/0233d12000c60yftm3D9F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235f12000c60zowkAE6F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230w12000c613uw4BF5D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-17', '城央绿意双床房', '双床房', '家庭亲子', 35, 1, 7, 6, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027f69e3c98b0941765cd8', '酒店环境很温馨、客服服务态度特别好、酒店空间很大、设备设施齐全、房间收拾打扫得一尘不染、而且酒店所处位置地段出行方便、很适合商务旅行', '["https://dimg04.c-ctrip.com/images/0236712000bs0kfj097C7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233j12000bs0lux4E78B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232w12000bs0lrr1960B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-29', '花园大床房', '大床房', '商务出差', 66, 0, 60, 7, '["整体满意度","前台服务","交通便利性"]'::jsonb, '整体满意度', '前台服务', '交通便利性'),
('68027f69e3c98b0941765cd9', '每次出差来广州都是入住这家酒店、环境好出行方便地铁淘金站就在酒店旁边……', '["https://dimg04.c-ctrip.com/images/0235012000c4oez396486_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236y12000c4ohq1v3380_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-14', '花园大床房', '大床房', '商务出差', 36, 0, 1, 6, '["交通便利性","整体满意度"]'::jsonb, '交通便利性', '整体满意度', NULL),
('68027f69e3c98b0941765cda', '位置、环境俱佳，硬件无可挑剔。最令人无语的就是二楼的特色餐厅荔湾亭，价钱贵，完全符合五星级收费标准，可惜出品比街边大排档还要低几个档次！现在的荔湾亭已经不是当年的荔湾亭了，连我这个地道广州人都感觉难以下咽！', '["https://dimg04.c-ctrip.com/images/0233812000bff3pn27AFB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235712000bff476p0963_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230n12000bff2dmz9F4E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235t12000bff4qod1E23_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233612000bff9c2tADA2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-06-16', '红棉大床套房', '套房', '商务出差', 103, 0, 42, 9, '["餐饮设施","价格合理性","整体满意度"]'::jsonb, '餐饮设施', '价格合理性', '整体满意度'),
('68027f69e3c98b0941765cdb', '房间很舒适，服务到位，遗漏的现金也通知我回去拿，非常满意', '["https://dimg04.c-ctrip.com/images/0236a12000caqc4yh17CB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-01', '红棉大床套房', '套房', '商务出差', 28, 0, 3, 7, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68027f69e3c98b0941765cdc', '客房免费升级为套房，酒店很安静，配套设施齐全，服务没话说，就是早餐人太多，要排队', '["https://dimg04.c-ctrip.com/images/0236512000c3og9nqD569_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232u12000c3oa7do3D35_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231712000c3oab0yAC4A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-10', '花园大床房', '大床房', '家庭亲子', 40, 0, 8, 7, '["整体满意度","安静程度","餐饮设施"]'::jsonb, '整体满意度', '安静程度', '餐饮设施'),
('68027f69e3c98b0941765cdd', '环境非常好??', '["https://dimg04.c-ctrip.com/images/0237312000d3tfn2m3C06_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230a12000d3tfjbg35A1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231412000d3tfkjbD1F4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-02', '花园大床房', '大床房', '商务出差', 7, 0, 7, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027f69e3c98b0941765cde', '酒店环境舒适，服务质量好。', '["https://dimg04.c-ctrip.com/images/0236k12000ch0jf4190F1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g12000ch0d69q3D54_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231212000ch0rc8yDD8E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-29', '花园大床房', '大床房', '独自旅行', 13, 0, 25, 3, '["整体满意度","前台服务","客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务'),
('68027f69e3c98b0941765cdf', '原来华为广州办事处也在这里，哈哈哈，大大的赞', '["https://dimg04.c-ctrip.com/images/0231l12000cchvh9dB19B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-07', '花园双床房', '双床房', '家庭亲子', 22, 0, 2, 2, '["周边配套"]'::jsonb, '周边配套', NULL, NULL),
('68027f69e3c98b0941765ce0', '早餐品种丰富', '["https://dimg04.c-ctrip.com/images/0233512000ckpabco345B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-15', '城央绿意双床房', '双床房', '朋友出游', 6, 0, 25, 3, '["餐饮设施"]'::jsonb, '餐饮设施', NULL, NULL),
('68027f69e3c98b0941765ce1', '酒店年久老旧，卫生间淋浴高仪水龙头水管滋水，马桶非电动圈。客房?香味难闻 由于客房数量众多，打扫慢。因位置入住率高。排队入住起码半小时以上。
还有个缺陷 是酒店附近再修地铁，（前台义正言辞说是政府工程）
客房非常受噪音的影响，建议携程预订时告知真实情况。
花园酒店对花园这边客房 要么不售卖 要么降价售卖 。而不是到酒店前台才告之 。广州酒店众多携程定1000+一晚上 因为噪音完全无法入睡。夜晚22:00见视频噪音
餐饮桃园馆 还不错。
昨日入住对面的友谊商店发生火灾，不宜停留。
这个价位还是去住珠江新城吧。', '["https://dimg04.c-ctrip.com/images/0200h12000bb6zdojBC82_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0232612000bb6j8ql0C22_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231a12000bb6vf3q6CF4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232012000bb6siauDB53_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2, 2, '2023-05-28', '红棉双床套房', '套房', '商务出差', 256, 3, 8, 9, '["房间设施","安静程度","退房/入住效率"]'::jsonb, '房间设施', '安静程度', '退房/入住效率'),
('68027f73e3c98b0941765ce2', '广州花园酒店不愧是老牌高档酒店之一，拉满仪式感的入口门廊，气派的大堂，第一印象非常好。办理入住时赶上酒店举办活动，等的时间有点长，和客服沟通后，工作人员迅速调整工作，很快解决问题。体验了一下露天泳池，下午五点太阳不晒，水温很适合，早餐一层的瀑布餐厅和二层的酒吧式餐厅各有特色。入住两天，感觉酒店的工作人员非常和善有礼，留下美好回忆。', '["https://dimg04.c-ctrip.com/images/0235z12000bg7y4rpA2BD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234012000bg81fkt601E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231v12000bg82t6rDC36_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235412000bg7xjfjB008_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231z12000bg83rw27266_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234j12000bg7x08t1BC9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-19', '城央绿意双床房', '双床房', '商务出差', 166, 0, 25, 9, '["整体满意度","前台服务","公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施'),
('68027f73e3c98b0941765ce3', '强烈推荐这家酒店性价比高，无论旅游都是一个不错的选择。服务非常好。前台Kasas 不错。   迎宾李文热情下次还会来继续住。', '["https://dimg04.c-ctrip.com/images/0233k12000jejsqpn4FB6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-29', '城央绿意双床房', '双床房', '其他', 62, 0, 3, 6, '["性价比","前台服务","整体满意度"]'::jsonb, '性价比', '前台服务', '整体满意度'),
('68027f73e3c98b0941765ce4', '干净，服务到位，周边环境热闹，有地铁', '["https://dimg04.c-ctrip.com/images/0235a12000ce6telbF5AA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-15', '城央绿意双床房', '双床房', '商务出差', 18, 0, 4, 5, '["卫生状况","前台服务","交通便利性"]'::jsonb, '卫生状况', '前台服务', '交通便利性'),
('68027f73e3c98b0941765ce5', '老牌五星环境不错，房间不大设施有点旧，总体不错', '["https://dimg04.c-ctrip.com/images/0232712000cd5dsk3118E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234d12000cd5dfpiE503_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-10-10', '花园双床房', '双床房', '家庭亲子', 23, 0, 6, 5, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL),
('68027f73e3c98b0941765ce6', '感觉很不错，床铺很舒服，升级了套房，房间很大', '["https://dimg04.c-ctrip.com/images/0230k12000cc40z8bD96C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231g12000cc45zye0D8B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230t12000cc44alnCA62_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237312000cc43pmeD722_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-05', '花园双床房', '双床房', '家庭亲子', 22, 0, 2, 5, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL)
